        componentsByType[item.type] = [];
      }
      componentsByType[item.type].push(index);
    }
  });

  for (const [_type, indices] of Object.entries(componentsByType)) {
    let i = 0;
    while (i < indices.length) {
      if (i + 3 <= indices.length) {
        // Check if we can form a block of 3
        basePremium += COMPONENT_BLOCK_PREMIUM;
        processedIndices.add(indices[i]);
        processedIndices.add(indices[i + 1]);
        processedIndices.add(indices[i + 2]);
        i += 3;
      } else {
        // Remaining components get normal premium
        for (let j = i; j < indices.length; j++) {
          basePremium += COMPONENT_BASE_PREMIUM;
          processedIndices.add(indices[j]);
        }
        break;
      }
    }
  }

  return { basePremium, processedIndices };
}

export function calculateQuote(input: QuoteInput): number {
  const { customer, items, isFirstInsurance } = input;

  if (items.length === 0) {
    return PROCESSING_FEE;
  }

  // Calculate base premium for components with block discounts
  const { basePremium: componentBasePremium, processedIndices } = calculateComponentBlocks(items);

  // Calculate base premium for regular items and unprocessed components
  let totalBasePremium = componentBasePremium;
  for (let i = 0; i < items.length; i++) {
    if (!processedIndices.has(i)) {
      totalBasePremium += getItemBasePremium(items[i].type);
    }
  }

  // Apply item-specific modifiers (curse and high enchantment)
  let premiumAfterItemModifiers = totalBasePremium;
  for (let i = 0; i < items.length; i++) {
    if (processedIndices.has(i)) continue; // Components don't get item-specific modifiers

    const item = items[i];
    const itemBase = getItemBasePremium(item.type);
    let itemModifier = 0;

    if (item.cursed) {
      itemModifier += itemBase * CURSE_SURCHARGE;
    }

    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
      itemModifier += itemBase * HIGH_ENCHANTMENT_SURCHARGE;
    }

    premiumAfterItemModifiers += itemModifier;
  }

  // Apply policy-wide modifiers
  let policyPremium = premiumAfterItemModifiers;

  // First insurance surcharge (10%)
  if (isFirstInsurance) {
    policyPremium += policyPremium * FIRST_INSURANCE_SURCHARGE;
  } else {
    // Follow-up contract discount (15%)
    policyPremium -= policyPremium * FOLLOW_UP_DISCOUNT;
  }

  // Loyalty discount (20% for customers with >= 2 years)
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
    policyPremium -= policyPremium * LOYALTY_DISCOUNT;
  }

  // Add processing fee
  const finalPremium = policyPremium + PROCESSING_FEE;

  // Round up to favor MHPCO
  return Math.ceil(finalPremium);
}

