export function calculateQuote(input: QuoteInput): number {
  const { customer, items, isFirstInsurance } = input;

  if (items.length === 0) {
    return PROCESSING_FEE;
  }

  // Calculate base premium for components with block discounts
  const { basePremium: componentBasePremium, processedIndices } = calculateComponentBlocks(items);

  // Build a list of items with their base premiums and modifiers
  const itemsWithPremiums: Array<{ base: number; modifiers: number }> = [];

  // Add regular items with their modifiers
  for (let i = 0; i < items.length; i++) {
    if (!processedIndices.has(i)) {
      const item = items[i];
      const itemBase = getItemBasePremium(item.type);
      let modifiers = 0;

      if (item.cursed) {
        modifiers += itemBase * CURSE_SURCHARGE;
      }

      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        modifiers += itemBase * HIGH_ENCHANTMENT_SURCHARGE;
      }

      itemsWithPremiums.push({ base: itemBase, modifiers });
    }
  }

  // Calculate total policy base premium
  let totalBasePremium = componentBasePremium;
  let totalModifiers = 0;
  for (const item of itemsWithPremiums) {
    totalBasePremium += item.base;
    totalModifiers += item.modifiers;
  }

  let policyPremium = totalBasePremium + totalModifiers;

  // Apply policy-wide modifiers
  // First insurance surcharge (10%)
  if (isFirstInsurance) {
    policyPremium += policyPremium * FIRST_INSURANCE_SURCHARGE;
  } else {
    // Follow-up contract discount (15%)
    policyPremium -= policyPremium * FOLLOW_UP_DISCOUNT;
  }

  // Loyalty discount (20% for customers with >= 2 years)
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
    policyPremium -= policyPremium * LOYALTY_DISCOUNT;
  }

  // Add processing fee
  const finalPremium = policyPremium + PROCESSING_FEE;

  // Round up to favor MHPCO
  return Math.ceil(finalPremium);
}

