        // Remaining components get normal premium
        for (let j = i; j < indices.length; j++) {
          basePremium += COMPONENT_BASE_PREMIUM;
          processedIndices.add(indices[j]);
        }
        break;
      }
    }
  }

  return { basePremium, processedIndices };
}

